INSERT INTO books (id, acc_no, author, title, call_no, subject, location, description, cover_color, tags) VALUES
(1,'B2735','STREETMAN, BEM.G.','SOLID STATE ELECTRONIC DEVICES','621.3815STR','ELECTRONICS','5//1','A comprehensive textbook covering the physics and operation of semiconductor devices including diodes, transistors, and MOSFETs. It bridges fundamental solid-state physics with practical electronic device applications. Widely used in undergraduate electronics and semiconductor courses.','#4338CA','electronics'),
(2,'B3594','KASAP, S.O.','PRINCIPLES OF MATERIALS AND DEVICES','621.382KAS','ELECTRONICS','5//1','Explores the electrical, optical, and magnetic properties of engineering materials from a modern physics perspective. Covers semiconductors, dielectrics, and superconductors with real-world device applications. An essential reference for materials science and electronics students.','#374151','electronics'),
(3,'B3668','KASAP, S.O.','PRINCIPLES OF ELECTRONICS MATERIALS & DEVICES','621.382KAS','ELECTRONICS','5//1','An in-depth study of electronic materials including semiconductors, conductors, and insulators with a focus on device behavior. Kasap presents quantum mechanical foundations alongside practical engineering applications. Highly recommended for advanced undergraduate and graduate students.','#374151','electronics'),
(4,'B3697','MEHTA, V.K.','PRINCIPLES OF ELECTRICAL ENGINEERING & ELECTRONICS','621.381MEH','ELECTRONICS','5//1','A well-structured introductory text covering fundamental concepts of electrical engineering and basic electronics in an accessible format. Topics include circuit theory, network analysis, semiconductor devices, and amplifiers. Popular among engineering students for its clarity and comprehensive coverage.','#374151','electronics'),
(5,'D905','KANI, A. NAGOOR','POWER SYSTEM ANALYSIS','621.3191KAN','ELECTRONICS','5//1','Covers the analysis of electrical power systems including load flow, fault analysis, stability, and protection. Presents mathematical models and computational techniques used in modern power engineering. An essential resource for electrical power engineering students and professionals.','#B91C1C','power'),
(6,'D915','HAYES, THOMAS C.','THE ART OF ELECTRONIC (STUDENT MANUAL)','621.381078HAY','ELECTRONICS','5//1','A hands-on student companion to the classic electronics text, providing practical circuit design exercises and problem sets. Emphasizes real-world electronic design intuition over pure mathematical theory. Helps students build practical skills alongside theoretical understanding.','#374151','electronics'),
(7,'D924','BHASKER, J.','VHDL PRIMER','621.392BHA','ELECTRONICS','5//1','An introductory guide to VHDL (VHSIC Hardware Description Language) for digital system design and simulation. Covers syntax, data types, modeling styles, and synthesis with clear examples. Essential for students learning digital design and FPGA/ASIC development.','#065F46','electronics'),
(8,'D1529','MAINI, ANIL K.','ELECTRONICS AND COMMUNICATION SIMPLIFIED','621.382MAI','ELECTRONICS','5//1','A concise yet thorough overview of electronics and communication engineering topics suitable for exam preparation. Covers analog circuits, digital systems, signals, and communication fundamentals in a simplified manner. Useful for students preparing for competitive technical examinations.','#0369A1','communication'),
(9,'D1641','RAJPUT, R.K.','A TEXT BOOK OF POWER PLANT ENGINEERING','621.3121RAJ','ELECTRONICS','5//1','Covers the design, operation, and maintenance of thermal, hydro, nuclear, and other power plants comprehensively. Includes topics on thermodynamic cycles, turbines, boilers, and environmental considerations. A standard reference text for mechanical and electrical power engineering students.','#B91C1C','power'),
(10,'B2231','FRENZEL, E. LOUIS','PRINCIPLES OF ELECTRONIC COMMUNICATION SYSTEMS','384.5FRE','ELECTRONICS','5//2','Introduces modern electronic communication systems including AM, FM, digital modulation, and fiber optics. Frenzel presents complex topics in a clear, practical manner with relevant industry examples. Widely adopted in communication engineering courses at undergraduate level.','#0369A1','communication'),
(11,'B3277','SEN, P.C.','PRINCIPLES OF ELECTRONICS MACHIES & POWER ELECTRONICS','621.3104SEN','ELECTRONICS','5//2','A thorough treatment of electrical machines including DC motors, induction motors, synchronous machines, and transformers. Also covers power electronic converters and their application in drive systems. A standard textbook for power electronics and electrical machines courses.','#B91C1C','power'),
(12,'B3624','RAM, BADRI','POWER SYSTEM PROTECTION & SWITCHGEAR','621.317RAM','ELECTRONICS','5//2','Explains the principles and practices of protecting power systems using relays, circuit breakers, and switchgear equipment. Covers various protection schemes for generators, transformers, transmission lines, and buses. A vital reference for power systems protection engineers and students.','#B91C1C','power'),
(13,'B4574','BAYUK, JENNIFER L.','CYBER SECURITY POLICY GUIDE BOOK','005.8BAY','ELECTRONICS','5//2','Provides a practical framework for developing and implementing organizational cybersecurity policies. Covers risk management, compliance, governance, and best practices for securing digital infrastructure. Essential reading for IT managers, security professionals, and policy makers.','#374151','electronics'),
(14,'B4820','TABU, HERBERT','TABU''S PRINCIPLES OF COMMUNICATION SYSTEM','621.38TAU','ELECTRONICS','5//2','Presents fundamental principles of communication systems including modulation, demodulation, noise analysis, and digital techniques. Offers clear explanations supported by worked examples and problem sets. A useful textbook for students in electronics and communication engineering programs.','#0369A1','communication'),
(15,'B4871','FRENZEL, LOUIS E.','PRINCIPLES OF ELECTRONIC COMMUNICATION SYSTEM','621.382FRE','ELECTRONICS','5//2','Provides comprehensive coverage of electronic communication systems from analog modulation to modern digital communication standards. Includes practical examples, system diagrams, and performance analysis methods. A reliable text for undergraduate communication engineering courses.','#0369A1','communication'),
(16,'B5432','CASTANGER, LUIS','UNDERSTANDING MEMS: PRINCIPLES & APPLICATIONS','681.2CAS','ELECTRONICS','5//2','An introduction to Micro-Electro-Mechanical Systems (MEMS), covering fabrication, design, and sensing applications. Explores applications in automotive, biomedical, and consumer electronics industries. Essential for students and engineers working in microfabrication and nanotechnology.','#374151','electronics'),
(17,'D1505','CHAKRABARTI, N.B. & DATTA, A.K.','AN INTRODUCTION TO THE PRINCIPLES OF DIGITAL COMMUNICATIONS','621.382CHA','ELECTRONICS','5//2','Introduces the mathematical foundations and system concepts underlying digital communication systems. Topics include source coding, channel coding, modulation, and error correction techniques. Appropriate for senior undergraduate and graduate students in communication engineering.','#065F46','digital,communication'),
(18,'D1515','GUPTA, S.R.','RAILWAY RECRUITMENT BOARD EXAMINATION','001.076GUP','ELECTRONICS','5//2','A comprehensive guide for candidates preparing for Railway Recruitment Board (RRB) technical examinations in India. Covers electronics, communication, and general engineering topics with practice questions and solved examples. Useful for job aspirants targeting Indian Railways technical positions.','#374151','electronics'),
(19,'D1518','PROAKIS, JOHN G.','CONTEMPORARY COMMUNICATION SYSTEMS USING MATLAB','621.38216PRO','ELECTRONICS','5//2','Bridges communication theory with practical simulation using MATLAB as the primary computational tool. Covers analog and digital communication systems with hands-on MATLAB-based examples and projects. Ideal for students learning communications with a simulation-based approach.','#0369A1','communication,MATLAB'),
(20,'D1522','HSU, HWEI P.','ANALOG AND DIGITAL COMMUNICATION','621.38223HSU','ELECTRONICS','5//2','A balanced treatment of both analog and digital communication systems including modulation techniques and signal processing. Hsu presents topics with mathematical rigor while maintaining clarity through examples and diagrams. A solid reference for communication engineering students and practitioners.','#065F46','digital,communication,analog'),
(21,'D1523','SINGH, RENU & SINGH, B.P.','MICROPROCESSORS INTERFACING AND APPLICATION','TK7895.M5SIN','ELECTRONICS','5//2','Covers microprocessor architecture, assembly language programming, and hardware interfacing techniques for embedded applications. Discusses 8085 and 8086 processors with peripheral devices and real-world interface circuits. A practical guide for students learning microprocessor-based system design.','#7C3AED','microprocessors'),
(22,'D1527','BHATTACHARYA, AMITABHA','DIGITAL COMMUNICATION','621.382BHA','ELECTRONICS','5//2','Provides a systematic treatment of digital communication principles including source coding, channel coding, and modulation. Covers modern techniques such as spread spectrum, OFDM, and error-correcting codes. Suitable for graduate students and practicing engineers in digital communications.','#065F46','digital,communication'),
(23,'B4804','MOHANNED','DESIGN','621.381MOH','ELECTRONICS','5//3','Explores engineering and electronic design principles including system-level design methodologies and circuit synthesis. Covers design tools, simulation methods, and product development processes. A useful reference for engineering students learning structured design approaches.','#374151','electronics'),
(24,'B4916','KUMAR, LASHOK','POWER ELECTRONICS WITH MATLAB','658.05KUM','ELECTRONICS','5//3','Integrates MATLAB and Simulink simulations into the study of power electronic circuits and systems. Covers converters, inverters, and drive systems with practical simulation examples and case studies. Ideal for students and engineers who want to validate power electronics designs computationally.','#B91C1C','power,MATLAB'),
(25,'B5012','KUNDUR, PRABHA','POWER SYSTEM STABILITY AND CONTROL','658.05KUN','ELECTRONICS','5//3','A landmark reference on power system stability analysis, covering transient, voltage, and small-signal stability in depth. Kundur''s work is widely regarded as one of the most authoritative texts in power systems engineering. Essential reading for advanced power systems engineers and researchers.','#B91C1C','power,control'),
(26,'B5017','KOTHARI, D.P.','POWER SYSTEM ENGINEERING','621.4021KOT','ELECTRONICS','5//3','Covers the generation, transmission, distribution, and analysis of electric power systems comprehensively. Kothari and Nagrath''s text is a standard in Indian universities for power systems courses. Includes load flow, fault analysis, economic dispatch, and power system protection.','#B91C1C','power'),
(27,'B5020','KOTHARI, D.P.','POWER ELECTRONICS','621.381BIM','ELECTRONICS','5//3','Introduces the theory and application of power electronic circuits including rectifiers, inverters, choppers, and cycloconverters. Covers semiconductor switching devices and their control strategies for industrial applications. A standard undergraduate text for power electronics courses.','#B91C1C','power'),
(28,'D910','RASHID, MUHAMMAD H.','POWER ELECTRONICS, CIRCUITS, DEVICES & APPLICATION','621.381RAS','ELECTRONICS','5//3','A comprehensive reference on power electronics covering device characteristics, converter topologies, and control methods. Rashid provides extensive coverage of AC and DC drives, UPS systems, and renewable energy applications. Widely used in advanced power electronics courses worldwide.','#B91C1C','circuits,power'),
(29,'D913','BIMBHRA, P.S.','POWER PLANT ENGINEERING','621.3121NAG','ELECTRONICS','5//3','Covers the engineering principles behind thermal, hydro, nuclear, and renewable power generation systems. Includes thermodynamic analysis, plant design, fuel systems, and environmental impact considerations. A standard text for mechanical and power engineering students.','#B91C1C','power'),
(30,'D928','NAG, P.K.','A COURSE IN POWER PLANT ENGINEERING','621.3121ARO','ELECTRONICS','5//3','A concise and practical guide to the design and operation of various types of power generating plants. Covers boilers, steam turbines, condensers, cooling towers, and plant instrumentation. Useful for engineering students and power plant operation professionals.','#B91C1C','power'),
(31,'D929','ARORA, S.C.','POWER DEVICES AND MACHINES','621.3121CHI','ELECTRONICS','5//3','Examines the operating principles of electrical power devices and rotating machines including motors and generators. Covers torque-speed characteristics, equivalent circuits, and efficiency analysis. A solid foundational text for electrical machines courses.','#B91C1C','power'),
(32,'D930','ARORA, S.C.','APPLIED MULTI MENSIONAL SYSTEMS THEORY','003BOS','ELECTRONICS','5//3','Explores multidimensional systems and signal processing with applications in image processing and control. Covers mathematical foundations including polynomial matrices and stability theory for ND systems. A specialized reference for graduate students in systems theory and signal processing.','#374151','electronics'),
(33,'D1097','CHITODE, J.S.','ELECTRONIC DEVICES AND CIRCUITS','621.3815GUP','ELECTRONICS','5//3','Provides a thorough introduction to electronic devices such as diodes, BJTs, FETs, and operational amplifiers. Includes practical circuit analysis and design techniques with worked examples. A commonly used undergraduate textbook in electronics engineering programs.','#166534','circuits'),
(34,'D1526','BOSE, N.K.','MICRO ELECTRONIC CIRCUITS','621.3815ED','ELECTRONICS','5//4','An authoritative text on microelectronics covering device physics, analog circuit design, and digital electronics. Bose presents semiconductor devices and amplifier circuits with mathematical depth and practical insight. Suitable for advanced undergraduate and graduate microelectronics courses.','#7C3AED','circuits'),
(35,'B304','GRAINGER, JOHN J.','SIGNALS AND SYSTEMS','621.3191GRA','ELECTRONICS','5//4','Covers continuous-time and discrete-time signal analysis, Fourier transforms, Laplace transforms, and Z-transforms. Grainger''s treatment emphasizes both theoretical understanding and practical application in engineering systems. A core textbook for signals and systems courses in electrical engineering.','#0369A1','signals'),
(36,'B5101','GRAINGER, JOHN J.','SIGNALS & SYSTEMS','621.3820PP','ELECTRONICS','5//4','Provides foundational coverage of signal representation, system properties, convolution, and frequency domain analysis. Includes coverage of sampling, modulation, and filter design with clear mathematical treatment. A standard reference for electrical engineering students studying signals and systems.','#0369A1','signals'),
(37,'D825','HAYES, MONSON H.','STATISTICAL DIGITAL SIGNAL PROCESSING AND MODELING','621.3822HAY','ELECTRONICS','5//5','Covers statistical signal processing methods including optimal filtering, spectral estimation, and adaptive algorithms. Hayes bridges classical deterministic signal processing with statistical approaches for real-world applications. Recommended for graduate students in digital signal processing and communications.','#065F46','digital,signals'),
(38,'D839','HAYES, MOUSON H.','STATISTICAL DIGITAL SIGNAL PROCESSING & MODELING','621.317OPP','ELECTRONICS','5//5','An advanced treatment of statistical methods applied to digital signal processing and system modeling. Covers power spectral estimation, Wiener filters, Kalman filters, and AR/MA modeling. A rigorous graduate-level text for DSP researchers and advanced students.','#065F46','digital,signals'),
(39,'B5034','RABINER, LAWRENCE R.','THEORY & APPLICATION OF DIGITAL SIGNAL PROCESSING','621.3822RAB','ELECTRONICS','5//5','A foundational text that established many core principles of digital signal processing theory and practice. Rabiner and Gold''s work covers DFT, FFT, digital filter design, and spectral analysis comprehensively. A landmark reference for both students and DSP engineers.','#065F46','digital,signals'),
(40,'D837','NAGRATH, L.J.','CONTROL SYSTEMS ENGINEERING','621.3822NAG','ELECTRONICS','5//5','A widely used undergraduate text on automatic control systems covering modeling, analysis, and design techniques. Nagrath and Gopal present root locus, Bode plots, Nyquist criteria, and state-space methods clearly. An essential textbook for control systems courses in engineering programs.','#1D4ED8','control'),
(41,'B259','FOROUZAN, BEHROUZ A.','DATA COMMUNICATIONS AND NETWORKING','004.6FOR','COMPUTER','5//6','Provides comprehensive coverage of data communication protocols, network architectures, and the OSI and TCP/IP models. Forouzan''s text is known for its clear explanations of physical, data link, network, and transport layers. A standard textbook for computer networking courses.','#0369A1','communication,networking'),
(42,'B4131','ROBERTS, MICHAEL J.','FUNDAMENTALS OF SIGNALS & SYSTEM','621.3822ROB','ELECTRONICS','5//6','Introduces the mathematical description of signals and linear systems in both time and frequency domains. Covers convolution, Fourier series, Laplace transforms, and system stability analysis. A solid introductory text for electrical engineering and computer engineering students.','#0369A1','signals'),
(43,'B4452','GHOSH, SAMARAIT','FUNDAMENTALS OF ELECTRICAL & ELECTRONICS ENGINEERING','621.3GHO','ELECTRONICS','5//6','Covers the essential principles of electrical circuits, machines, and basic electronics in a unified format. Presents topics such as DC and AC circuits, transformers, semiconductor devices, and amplifiers accessibly. A popular introductory reference for first-year engineering students.','#374151','electronics'),
(44,'D772','FAUSTT, LAURENE','FUNDAMENTALS OF NEURAL NETWORK','812.8FAU','ELECTRONICS','5//6','An introduction to artificial neural networks covering perceptrons, backpropagation, and learning algorithms. Fausett explores network architectures and their applications in pattern recognition and function approximation. Suitable for students beginning their study of neural computing and machine learning.','#92400E','networking'),
(45,'D898','GHOSH, SAMARAJIT','FUNDAMENTALS OF ELECTRICAL DEVICES','358.1241DUB','ELECTRONICS','5//6','Covers the operating principles and characteristics of fundamental electrical and electronic devices. Topics include diodes, transistors, thyristors, and their use in practical circuit applications. A useful reference for students studying electronics and electrical device behavior.','#374151','electronics'),
(46,'D1355','SADIKU, MATHEW','PRINCIPLES OF ELECTROMAGNETICS','005.1175AD','ELECTRONICS','5//6','Presents electromagnetic theory from fundamental laws to engineering applications including waveguides and antennas. Sadiku''s text is known for its pedagogical clarity and use of MATLAB-based problem solving. A widely adopted undergraduate text for electromagnetics courses worldwide.','#6D28D9','electromagnetics'),
(47,'D1524','FOROUZAN, BEHROUZ A.','TCP/IP PROTOCOL SUITE','004.62FOR','ELECTRONICS','5//6','A detailed reference on the TCP/IP protocol family covering all major protocols from IP addressing to application-layer services. Forouzan explains complex networking protocols with clear diagrams and examples. Essential reading for students and professionals in networking and internet technologies.','#374151','electronics'),
(48,'D1965','SALIVAHANAN, S.','ELECTONIC DEVICES & CIRCUITS','621.3815SAL','ELECTRONICS','5//6','Covers the theory and application of electronic devices including diodes, bipolar transistors, and FETs. Salivahanan presents circuit analysis methods and device models with practical engineering context. A commonly used undergraduate textbook in electronics and communication programs.','#166534','circuits'),
(49,'D1985','LATHI, B.P.','MODERN DIGITAL AND ANALOG COMMUNICATION SYSTEMS','621.382LAT','ELECTRONICS','5//6','A classic text on communication systems that covers both analog and digital techniques in a unified framework. Lathi''s treatment includes AM/FM, digital modulation, spread spectrum, and source coding with mathematical rigor. One of the most widely referenced communication engineering textbooks.','#065F46','digital,communication,analog'),
(50,'D1989','PROAKIS, JOHN G.','ALGORITHM & APPLICATION','621.3822PRO','ELECTRONICS','5//6','Covers algorithmic techniques and their applications in signal processing and communication systems. Includes efficient computational methods for signal analysis, filter implementation, and system design. Useful for students and engineers working on digital signal processing applications.','#374151','electronics'),
(51,'B159','GRIFFITHS, DAVID J.','INTRODUCTION TO ELECTRODYNAMICS','537.6GRI','ELECTRONICS','5//7','Griffiths'' highly acclaimed text presents classical electromagnetism with mathematical elegance and physical insight. Covers electrostatics, magnetostatics, electromagnetic waves, and radiation through clear explanations and engaging problems. A beloved standard text for undergraduate physics and engineering electromagnetics courses.','#6D28D9','electronics'),
(52,'B165','GRIFFITHS, DAVID J.','INDUCTION TO ELECTRODYNAMICS','537.6GRI','ELECTRONICS','5//7','Covers the foundational concepts of electromagnetic induction and electrodynamics including Faraday''s law and Maxwell''s equations. Griffiths presents the material with characteristic clarity, connecting theory to physical phenomena. A well-regarded reference for physics and electrical engineering students.','#6D28D9','electronics'),
(53,'B3820','MILLMAN, JACOB','MILLMAN''S INTEGRATED ELECTRONICS','621.381MIL','ELECTRONICS','5//7','A classic electronics textbook covering analog and digital integrated circuits, device physics, and amplifier design. Millman and Halkias laid foundational principles for generations of electronics engineers. Still widely referenced for its thorough treatment of BJT and FET circuits.','#374151','electronics'),
(54,'D827','ROBERTS, MICHAEL J.','ELECTRONIC MEASUREMENTS AND INSTRUMENTATION','621.38GNA','ELECTRONICS','5//7','Covers principles and techniques of electronic measurement including sensors, signal conditioning, and data acquisition. Includes topics on oscilloscopes, spectrum analyzers, bridges, and digital measurement instruments. A practical reference for metrology and instrumentation engineering students.','#9D174D','instrumentation,measurement'),
(55,'D847','GNANAVADIVEL, J.','INTEGRATED CIRCUITS','621.38173CHO','ELECTRONICS','5//7','Explores the design, fabrication, and application of analog and digital integrated circuits. Covers op-amps, logic families, timers, and application-specific ICs with practical design guidelines. A useful textbook for students studying IC design and microelectronics.','#166534','circuits'),
(56,'D855','BOTKAR, K.R.','LINEAR INTEGRATED CIRCUITS','621.3819DOR','ELECTRONICS','5//7','Focuses on the analysis and application of linear ICs including operational amplifiers, voltage regulators, and comparators. Botkar presents numerous practical circuit configurations with design examples and applications. A standard reference for linear electronics and IC applications courses.','#166534','circuits'),
(57,'D856','DORF, RICHARD C.','INTRODUCTION TO ELECTROMAGNETIC','530.141CHE','ELECTRONICS','5//7','Provides an accessible introduction to electromagnetic theory including electric and magnetic fields, Maxwell''s equations, and waves. Covers antenna principles and electromagnetic compatibility for engineering applications. Suitable for students needing a solid foundation in applied electromagnetics.','#6D28D9','electromagnetics'),
(58,'D860','GRIFFITHS, DAVID J.','ELECTRONIC DEVICE & CIRCUITS','621.382COU','ELECTRONICS','5//7','Covers semiconductor device characteristics and their application in electronic circuit design. Topics include diode circuits, amplifier configurations, oscillators, and feedback systems. A concise and practical text for undergraduate electronics engineering students.','#166534','circuits'),
(59,'D931','CHENG, DAVID K.','DIGITAL & ANALOG COMMUNICATION SYSTEMS','621.3192SON','ELECTRONICS','5//7','Bridges analog and digital communication theory with practical system design considerations. Covers modulation, demodulation, channel coding, and receiver design with engineering depth. A useful reference for communication engineers and senior undergraduate students.','#065F46','digital,communication,analog'),
(60,'D934','SHARMA, SANJAY','CIRCUITS AND SYSTEMS','621.31PAD','ELECTRONICS','5//7','Introduces circuit analysis techniques and linear system theory in both time and frequency domains. Covers nodal and mesh analysis, Thevenin/Norton theorems, and Laplace transform methods. A solid foundational text for electrical engineering students.','#166534','circuits'),
(61,'D1503','COUCH, LEON W.','FUNDAMENTALS OF SIGNALS AND SYSTEM USING THE WAB AND MATLAB','621.3822KAM','ELECTRONICS','5//7','Combines traditional signals and systems theory with MATLAB-based computational methods and visualization. Covers continuous and discrete systems, transform analysis, and filter design with software tools. Ideal for students learning signals and systems with a hands-on computational approach.','#0369A1','signals,MATLAB'),
(62,'D1506','SONI, K.M.','MILLMAN''S ELECTRONIC DEVICES AND CIRCUITS','621.3815MIL','ELECTRONICS','5//7','A timeless reference covering semiconductor devices, amplifiers, oscillators, and digital logic circuits. Millman''s classic work remains relevant for its thorough device physics and circuit analysis content. Recommended for students and engineers who need a deep understanding of electronics fundamentals.','#166534','circuits'),
(63,'D1517','PRASAD, K.D.','ELECTRO MAGNETIC FIELDS AND WAVES','530.141PRA','ELECTRONICS','5//7','Covers the theory of electromagnetic fields including Coulomb''s law, Gauss''s law, Ampere''s law, and electromagnetic wave propagation. Prasad presents the mathematical framework with engineering applications in transmission lines and waveguides. A recommended text for undergraduate electromagnetics courses.','#374151','electronics'),
(64,'D1547','SHARMA, SANJAY','COMMUNICATION SYSTEMS (ANALOG & DIGITAL)','621.382SHA','ELECTRONICS','5//7','Provides comprehensive coverage of analog and digital communication principles including modulation, noise analysis, and system performance. Sharma presents both theoretical concepts and practical system design considerations. A useful textbook for communication engineering students at the undergraduate level.','#065F46','digital,communication,analog'),
(65,'B166','KENNEDY, GEORGE','KENNEDY''S ELECTRONIC COMMUNICATION SYSTEMS','621.38KEN','ELECTRONICS','5//8','A classic reference on electronic communication systems covering AM, FM, SSB, pulse modulation, and digital systems. Kennedy''s work is well-regarded for its thorough treatment of transmitters, receivers, and propagation. A widely used textbook in communication engineering programs.','#0369A1','communication'),
(66,'B3289','SIVANANDAM, S.N.','PRINCIPLES OF SOFT COMPUTING','006.3SIV','ELECTRONICS','5//8','Introduces soft computing techniques including fuzzy logic, neural networks, and evolutionary computation algorithms. Covers applications in pattern recognition, optimization, and intelligent system design. A foundational text for students studying artificial intelligence and computational intelligence.','#374151','electronics'),
(67,'D887','KENNEDY, GEORGE','ELECTRONIC COMMUNICATION SYSTEMS','621.382KEN','ELECTRONICS','5//8','A comprehensive text on electronic communication covering radio frequency systems, modulation techniques, and modern digital communication. Kennedy''s authoritative style makes complex communication concepts accessible to engineering students. Covers practical transmitter and receiver design with frequency spectrum considerations.','#0369A1','communication'),
(68,'D935','EDMINISTER, JOSEPH A.','ELECTROMAGNETICS','621.3822EDM','ELECTRONICS','5//8','Covers classical electromagnetic theory using Schaum''s outline format with solved problems and concise theory. Edminister''s text is valuable for students who need a problem-solving focused approach to learning electromagnetics. A popular supplement to standard electromagnetics textbooks.','#6D28D9','electromagnetics'),
(69,'D1356','EDMINISTER, JOSHEP A.','ELECTROMAGNETIC (SCHAUMS)','621.3822EDM','ELECTRONICS','5//8','A Schaum''s Outline providing concise theory and a large collection of solved problems in electromagnetics. Covers electric and magnetic fields, Maxwell''s equations, and electromagnetic wave propagation systematically. An excellent study guide and problem-solving companion for electromagnetics courses.','#6D28D9','electromagnetics'),
(70,'D1496','DAS, MULLICK','PRINCIPLES OF DIGITAL COMMUNICATION','621.35DAS','ELECTRONICS','5//8','Examines the principles underlying digital communication systems including information theory, source coding, and channel coding. Das and Mullick present modulation, detection, and error correction with mathematical rigor. Suitable for senior undergraduate and graduate communication engineering students.','#065F46','digital,communication'),
(71,'D1497','JAMWAL, GHANEKAR','DIGITAL CIRCUITS AND SYATEMS','621.38173JAM','ELECTRONICS','5//8','Covers combinational and sequential logic circuit design using Boolean algebra, Karnaugh maps, and state machines. Includes flip-flops, registers, counters, and programmable logic devices with design examples. A standard undergraduate textbook for digital electronics and digital system design.','#065F46','circuits,digital'),
(72,'D1498','MATHUR, ADITYA P.','INTRODUCTION TO MICRO PROCESS','621.3916MAT','ELECTRONICS','5//8','An introductory text on microprocessor architecture, instruction sets, and basic programming concepts. Covers 8-bit and 16-bit processors with assembly language programming and simple interfacing. Suitable for students beginning their study of microprocessors and embedded computing.','#374151','electronics'),
(73,'D1501','SINHA, UMESH AND RAJESH','COMMUNICATION NETWORK','621.38215IN','ELECTRONICS','5//8','Covers the architecture, protocols, and performance analysis of communication networks including LANs, WANs, and the internet. Topics include switching, routing, queuing theory, and network security fundamentals. A useful reference for students studying data communications and network engineering.','#0369A1','communication,networking'),
(74,'D1512','PADMANABHAN, K.','A TEXT BOOK ON SIGNALS AND SYSTEMS','621.31PAD','ELECTRONICS','5//8','Provides a structured introduction to continuous-time and discrete-time signals, system analysis, and transform methods. Covers Fourier series, Fourier transforms, Laplace transforms, and Z-transforms with engineering applications. A helpful textbook for undergraduate signals and systems courses.','#0369A1','signals'),
(75,'D1539','CHADHO, PREM R.','QUESTION BANK IN ELECTRONICS AND COMMUNICATION ENGINEERING','621.38CHA','ELECTRONICS','5//8','A collection of objective and descriptive questions covering all major topics in electronics and communication engineering. Organized by subject for systematic exam preparation including GATE and university examinations. A valuable resource for students preparing for competitive technical examinations.','#0369A1','communication'),
(76,'D1551','GORDON, GEOFFREY','SYSTEM SIMULATION','001.424GOR','ELECTRONICS','5//8','Covers the theory and practice of discrete-event simulation for modeling complex systems. Gordon presents simulation methodologies, statistical analysis of results, and practical simulation language use. A foundational reference for industrial engineering and operations research students.','#374151','electronics'),
(77,'B49','HALL, DOUGLAS V.','MICROPROCESSORS AND INTERFACING PROGRAMMING AND HARDWARE','005.26HAL','ELECTRONICS','5//9','Covers microprocessor architecture, programming in assembly language, and hardware interfacing for system design. Hall presents 8086 and 8088 processor families with peripheral devices, interrupts, and I/O techniques. A widely used practical text for microprocessor and embedded systems courses.','#7C3AED','microprocessors'),
(78,'B186','SEDRA, ADEL S.','MICROELECTRONIC CIRCUITS THEORY AND APPLICATIONS','621.381SED','ELECTRONICS','5//9','A comprehensive and rigorous treatment of microelectronic circuit analysis and design by globally recognized authors. Sedra and Smith cover amplifiers, filters, feedback, and digital circuits with depth and mathematical precision. Considered one of the finest microelectronics textbooks at the undergraduate and graduate level.','#166534','circuits,microelectronics'),
(79,'B2337','POZAR, M. DAVID','MICROWAVE ENGINEERING','621.3813POZ','ELECTRONICS','5//9','An authoritative text on microwave circuit design covering transmission lines, waveguides, network analysis, and amplifier design. Pozar''s work is widely adopted in graduate-level microwave engineering courses worldwide. Includes modern topics like active microwave devices and microwave filter design.','#374151','electronics'),
(80,'B4802','KOTHARI, D.P.','MODERN POWER SYSTEM ANALYSIS','621.319KOT','ELECTRONICS','5//9','Covers the steady-state and dynamic analysis of modern interconnected power systems comprehensively. Topics include load flow, fault analysis, economic dispatch, and state estimation with MATLAB examples. A standard graduate-level reference for power systems engineering students and researchers.','#B91C1C','power'),
